import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(p1, p2):
        return np.linalg.norm(p1 - p2)

    def calculate_travel_time(distance, speed):
        return distance / speed

    best_node = None
    min_cost = float('inf')
    clusters = {}

    # Create clusters based on geographic proximity and urgency of time window
    for idx, customer_pos in enumerate(unvisited_customers):
        start_time, end_time = time_windows[idx]
        urgency = end_time - current_time
        cluster_key = int(urgency // 10)  # cluster by urgency in intervals of 10 time units
        if cluster_key not in clusters:
            clusters[cluster_key] = []
        clusters[cluster_key].append((idx, customer_pos, start_time, end_time))

    # Evaluate each cluster and select the customer with the best cost/benefit ratio within the closest urgent cluster
    sorted_clusters = sorted(clusters.items(), key=lambda x: x[0])  # sort by urgency

    for urgency, customers in sorted_clusters:
        for idx, pos, start_time, end_time in customers:
            distance = calculate_distance(cur_truck_pos, pos)
            travel_time = calculate_travel_time(distance, truck_speed)
            arrival_time = current_time + travel_time
            cost = max(start_time - arrival_time, 0) * 1.1  # cost of waiting
            cost += max(arrival_time - end_time, 0) * 100  # high penalty for missing the window
            cost += distance * 0.05  # include distance in the cost

            if cost < min_cost:
                min_cost = cost
                best_node = idx

    return best_node
